import okhttp3.*
import java.security.cert.X509Certificate
import javax.net.ssl.SSLContext
import javax.net.ssl.TrustManager
import javax.net.ssl.X509TrustManager

class IoTHttpClient {
    private val client: OkHttpClient
    
    init {
        val trustAllCerts = arrayOf<TrustManager>(
            object : X509TrustManager {
                override fun checkClientTrusted(chain: Array<X509Certificate>, authType: String) {}
                override fun checkServerTrusted(chain: Array<X509Certificate>, authType: String) {}
                override fun getAcceptedIssuers(): Array<X509Certificate> = arrayOf()
            }
        )
        
        val sslContext = SSLContext.getInstance("SSL")
        sslContext.init(null, trustAllCerts, java.security.SecureRandom())
        val sslSocketFactory = sslContext.socketFactory
        
        client = OkHttpClient.Builder()
            .sslSocketFactory(sslSocketFactory, trustAllCerts[0] as X509TrustManager)
            .hostnameVerifier { _, _ -> true }
            .build()
    }
    
    fun sendRequest(url: String, method: String, body: RequestBody? = null): Response {
        val requestBuilder = Request.Builder()
            .url(url)
        
        when (method.uppercase()) {
            "GET" -> requestBuilder.get()
            "POST" -> requestBuilder.post(body ?: RequestBody.create("", MediaType.parse("text/plain")))
            "PUT" -> requestBuilder.put(body ?: RequestBody.create("", MediaType.parse("text/plain")))
            "DELETE" -> requestBuilder.delete()
        }
        
        return client.newCall(requestBuilder.build()).execute()
    }
    
    fun sendIoTRequest(deviceIp: String, port: Int = 80, path: String, method: String, body: String? = null): Response {
        val url = if (port == 443) {
            "https://$deviceIp:$port$path"
        } else {
            "http://$deviceIp:$port$path"
        }
        
        val requestBody = body?.let {
            RequestBody.create(it, MediaType.parse("application/json"))
        }
        
        return sendRequest(url, method, requestBody)
    }
    
    fun sendCloudRequest(endpoint: String, method: String, body: String? = null): Response {
        val url = "https://api.example.com$endpoint"
        val requestBody = body?.let {
            RequestBody.create(it, MediaType.parse("application/json"))
        }
        
        return sendRequest(url, method, requestBody)
    }
}